// GitHub Authorization Code flow — Node.js backend (no framework)
// Requires: npm install node-fetch (or use native fetch in Node 18+)

const CLIENT_ID     = process.env.GITHUB_CLIENT_ID;
const CLIENT_SECRET = process.env.GITHUB_CLIENT_SECRET;
const REDIRECT_URI  = 'https://my-agent.example.com/auth/github/callback';

// --- Step 1: Build the authorization URL (send to user's browser) ---
function buildGitHubAuthURL(state) {
  const params = new URLSearchParams({
    client_id:    CLIENT_ID,
    redirect_uri: REDIRECT_URI,
    scope:        'repo read:user',   // Only request needed scopes
    state,                            // CSRF token
  });
  return `https://github.com/login/oauth/authorize?${params}`;
}

// --- Step 2: Exchange authorization code for access token ---
async function exchangeCodeForToken(code, state, expectedState) {
  if (state !== expectedState) {
    throw new Error('OAuth state mismatch — possible CSRF attack');
  }

  const resp = await fetch('https://github.com/login/oauth/access_token', {
    method:  'POST',
    headers: {
      'Content-Type': 'application/json',
      'Accept':       'application/json',
    },
    body: JSON.stringify({
      client_id:     CLIENT_ID,
      client_secret: CLIENT_SECRET,
      code,
      redirect_uri:  REDIRECT_URI,
    }),
  });

  const data = await resp.json();
  if (data.error) throw new Error(`Token exchange failed: ${data.error_description}`);

  // GitHub access tokens do not expire (unless fine-grained PAT is used)
  // and the response includes no refresh_token by default
  return {
    accessToken: data.access_token,
    scope:       data.scope,
    tokenType:   data.token_type,
  };
}

// --- Step 3: Call the GitHub API ---
async function getAuthenticatedUser(accessToken) {
  const resp = await fetch('https://api.github.com/user', {
    headers: {
      'Authorization': `Bearer ${accessToken}`,
      'Accept':        'application/vnd.github+json',
      'X-GitHub-Api-Version': '2022-11-28',
    },
  });
  if (!resp.ok) throw new Error(`GitHub API error: ${resp.status}`);
  return resp.json();
}

// --- Usage ---
(async () => {
  const state   = crypto.randomUUID();
  const authURL = buildGitHubAuthURL(state);
  console.log('Redirect user to:', authURL);

