# Production-style token manager with encryption and locking
import time
import json
from cryptography.fernet import Fernet

fernet = Fernet(os.environ["TOKEN_ENCRYPTION_KEY"].encode())


def encrypt(data: dict) -> bytes:
    return fernet.encrypt(json.dumps(data).encode())


def decrypt(ciphertext: bytes) -> dict:
    return json.loads(fernet.decrypt(ciphertext))


def ensure_fresh_token(db, user_id: str, provider: str) -> str:
    """Return a valid access token, refreshing if needed."""
    row = db.query(
        "SELECT * FROM oauth_tokens WHERE user_id=%s AND provider=%s",
        (user_id, provider),
    ).fetchone()

    if not row:
        raise ValueError(f"User {user_id} has not connected {provider}")

    token_data = decrypt(row["tokens_enc"])
    if time.time() < row["expires_at"] - 120:
        return token_data["access_token"]

    # Refresh
    resp = httpx.post(PROVIDER_TOKEN_URLS[provider], data={
        "grant_type":    "refresh_token",
        "refresh_token": token_data["refresh_token"],
        "client_id":     PROVIDER_CLIENT_IDS[provider],
        "client_secret": PROVIDER_CLIENT_SECRETS[provider],
    })
    if resp.status_code in (400, 401):
        db.execute(
            "UPDATE oauth_tokens SET revoked=true WHERE user_id=%s AND provider=%s",
            (user_id, provider),
        )
        raise PermissionError(f"Refresh token revoked for {user_id}/{provider}")

    new_tokens = resp.json()
    token_data["access_token"] = new_tokens["access_token"]
    if "refresh_token" in new_tokens:
        token_data["refresh_token"] = new_tokens["refresh_token"]

    db.execute(
        """UPDATE oauth_tokens
           SET tokens_enc=%s, expires_at=%s
           WHERE user_id=%s AND provider=%s""",
        (
            encrypt(token_data),
            time.time() + new_tokens["expires_in"] - 120,
            user_id,
            provider,
        ),
    )
    return new_tokens["access_token"]

